mapper.sql:
where s.tenant_id = #{tenantId} and s.del_flag = 0
and s.contract_id = #{contractId}
and ( s.channel_code like concat('%', #{keyword}, '%') or s.fetch_mode like concat('%', #{keyword}, '%') or s.endpoint like concat('%', #{keyword}, '%') or s.remote_path like concat('%', #{keyword}, '%') or c.contract_name like concat('%', #{keyword}, '%') or c.merchant_no like concat('%', #{keyword}, '%') or ch.channel_name like concat('%', #{keyword}, '%') or es.subject_name like concat('%', #{keyword}, '%') )
